//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Paragraph borders and shading (pBdr, shd, between/bar collapse)".
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO 29500 / MS-OI29500 for paragraph borders (`w:pBdr`) and shading
//! (`w:shd`). A FAILING assertion means stemma diverges from Word: it encodes a
//! real Word-compliance gap and must be traced to the source, NOT made to pass
//! by weakening the assertion.
//!
//! Methodology — consumption vs. save: stemma round-trips untouched content
//! byte-verbatim. `reserialize()` of an unedited document reflects stemma's
//! verbatim-preservation contract, not Word's render-time normalization.
//! Therefore `xmlContains`/`xmlOmits` here are used only for markup stemma
//! actively preserves/restructures (Annex A ordering, structural validity),
//! and consumption rules ("contributes no glyphs", "color defaults to auto")
//! are asserted on the READ side (`read_accepted`/`read_rejected`).

use std::io::{Cursor, Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude / plumbing ─────────────────────────────────────────────────────

/// Build a minimal, valid `.docx` package. `body_xml` is the inner content of
/// `<w:body>`. `extra_parts` is a list of `(part_name, xml)` (e.g.
/// `("word/styles.xml", "<w:styles…/>")`); each one also gets a content-types
/// override based on its part name.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Build content-types overrides for any extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part_name, _) in extra_parts {
        let ct = content_type_for(part_name);
        overrides.push_str(&format!(
            r#"<Override PartName="/{part_name}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // Document rels: point at any extra parts (styles/numbering) by guessed type.
    let mut doc_rel_entries = String::new();
    for (idx, (part_name, _)) in extra_parts.iter().enumerate() {
        let (rel_type, target) = doc_rel_for(part_name);
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{idx}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part_name, xml) in extra_parts {
            zip.start_file(*part_name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

fn content_type_for(part_name: &str) -> &'static str {
    if part_name.ends_with("styles.xml") {
        "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
    } else if part_name.ends_with("numbering.xml") {
        "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
    } else if part_name.ends_with("theme1.xml") {
        "application/vnd.openxmlformats-officedocument.theme+xml"
    } else {
        "application/xml"
    }
}

fn doc_rel_for(part_name: &str) -> (&'static str, &'static str) {
    if part_name.ends_with("styles.xml") {
        (
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
            "styles.xml",
        )
    } else if part_name.ends_with("numbering.xml") {
        (
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
            "numbering.xml",
        )
    } else {
        panic!("doc_rel_for: unsupported extra part {part_name}; add a relationship type for it")
    }
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse then serialize, returning the re-emitted `word/document.xml`.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "{ctx} — expected document to open clean (no validation errors), but got issues: {:?}",
        report.issues
    );
}

// ─── Tests ──────────────────────────────────────────────────────────────────

#[test]
fn explicit_none_border_edge_opens_clean_and_text_unchanged() {
    let body = r#"<w:p><w:pPr><w:pBdr><w:top w:val="none" w:sz="0" w:space="0" w:color="auto"/><w:bottom w:val="none" w:sz="0" w:space="0" w:color="auto"/></w:pBdr></w:pPr><w:r><w:t>Bordered text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "Bordered text",
        "§17.3.4 CT_Border / §17.18.2 ST_Border — val selects border style only; borders contribute no glyphs, so accepted text equals the run content."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "Bordered text",
        "§17.3.4 CT_Border / §17.18.2 ST_Border — no tracked changes present; rejecting yields the same run text, unaffected by the none border edges."
    );
    assert_opens_clean(
        &b,
        "§17.18.2 ST_Border / §17.3.1.24 pBdr — `none` is a member of the ST_Border enumeration, so the markup is schema-valid and Word opens it without repair.",
    );
}

#[test]
fn shd_color_auto_default_pattern_clear_text_unchanged() {
    let body = r#"<w:p><w:pPr><w:shd w:val="clear" w:fill="D9E2F3"/></w:pPr><w:r><w:t>Shaded paragraph</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "Shaded paragraph",
        "§17.3.5 CT_Shd / §17.18.78 ST_Shd — shading paints a background; with color omitted (auto) and val=clear it adds no glyphs, so accepted text equals the run content."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "Shaded paragraph",
        "§17.3.5 CT_Shd — no tracked changes; rejecting yields the same run text, unaffected by the clear/auto shading."
    );
    assert_opens_clean(
        &b,
        "§17.18.78 ST_Shd / §17.3.5 CT_Shd — `clear` is a valid ST_Shd value and an omitted color attribute is a defined default (auto), so the markup is schema-valid and Word opens it without repair.",
    );
}

#[test]
fn between_collapse_suppressed_when_border_sets_differ() {
    let body = r#"<w:p><w:pPr><w:pBdr><w:top w:val="single" w:sz="24" w:space="1" w:color="F2DCDB"/><w:bottom w:val="single" w:sz="24" w:space="1" w:color="F2DCDB"/></w:pBdr></w:pPr><w:r><w:t>First paragraph.</w:t></w:r></w:p><w:p><w:pPr><w:pBdr><w:top w:val="single" w:sz="24" w:space="1" w:color="F2DCDB"/><w:bottom w:val="single" w:sz="24" w:space="0" w:color="F2DCDB"/></w:pBdr></w:pPr><w:r><w:t>Second paragraph.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "§17.3.1.5 between / §17.3.1.7 bottom / §17.3.4 CT_Border — both paragraphs carry schema-valid CT_PBdr edges in Annex A order; differing bottom space (1 vs 0) suppresses the between collapse, and Word opens the document without repair.",
    );
}

#[test]
fn bar_border_consumption_no_glyphs_text_unchanged() {
    let body = r#"<w:p><w:pPr><w:pBdr><w:bar w:val="single" w:sz="24" w:space="1" w:color="4F81BD"/></w:pBdr></w:pPr><w:r><w:t>Mirror-margin paragraph</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "Mirror-margin paragraph",
        "§17.3.1.4 bar — the bar border is ignorable legacy decoration and contributes no glyphs, so accepted text equals the run content."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "Mirror-margin paragraph",
        "§17.3.1.4 bar — no tracked changes; rejecting yields the same run text, unaffected by the bar border."
    );
    assert_opens_clean(
        &b,
        "§17.3.4 CT_Border — `bar` carries a schema-valid CT_Border and sits last in the CT_PBdr sequence, so Word opens it without repair.",
    );
}

#[test]
fn shd_themefill_supersedes_literal_fill_roundtrip() {
    let body = r#"<w:p><w:pPr><w:shd w:val="clear" w:color="auto" w:fill="C3D69B" w:themeFill="accent3"/></w:pPr><w:r><w:t>Themed shading</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains(r#"w:themeFill="accent3""#),
        "§17.3.5 CT_Shd / §17.18.97 ST_ThemeColor — themeFill is the authoritative background reference and supersedes the literal fill; it must survive the roundtrip so Word can recompute the background from the theme part. Got XML: {xml}"
    );
    assert!(
        xml.contains(r#"w:fill="C3D69B""#),
        "§17.3.5 CT_Shd — the literal fill is the cached fallback for consumers that do not resolve themes; stemma must preserve it alongside themeFill so neither resolution path is broken. Got XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "§17.18.97 ST_ThemeColor / §17.18.38 ST_HexColor — themeFill is a valid ST_ThemeColor and fill a valid ST_HexColor; the shd is schema-valid and Word opens it without repair.",
    );
}

#[test]
fn para_shd_themefill_omitted_falls_back_to_fill() {
    let body = r#"<w:p><w:pPr><w:shd w:val="clear" w:color="auto" w:fill="C3D69B"/></w:pPr><w:r><w:t>Literal-fill shaded paragraph.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.144 (§17.4.32 shd) / ECMA §17.3.5 CT_Shd — a shd with val=clear, color=auto, fill=<hex> is a well-formed CT_Shd; with themeFill omitted Word resolves the background from the literal fill, and Word opens it without repair.",
    );
}

#[test]
fn para_border_omitted_sz_color_space_word_defaults_zero_auto() {
    let body = r#"<w:p><w:pPr><w:pBdr><w:top w:val="single"/></w:pBdr></w:pPr><w:r><w:t>Border with only a val attribute.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.38 (§17.3.1.4 bar) / ECMA §17.3.4 CT_Border — Word supplies defaults (color=auto, sz=0, space=0) for the omitted border attributes, so a val-only border is valid input and opens without repair.",
    );
    assert_eq!(
        accept_text(&b).trim(),
        "Border with only a val attribute.",
        "ECMA §17.3.4 CT_Border / §17.3.1.42 top — borders contribute no glyphs; with Word's defaulted sz=0/color=auto the edge changes only layout, so the consumed paragraph text equals the run text."
    );
}

#[test]
fn para_border_sz_out_of_range_opens_clean() {
    let body = r#"<w:p><w:pPr><w:pBdr><w:bottom w:val="single" w:sz="200" w:space="1" w:color="000000"/></w:pBdr></w:pPr><w:r><w:t>oversized border</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ECMA §17.3.4 CT_Border / §17.18.23 ST_EighthPointMeasure — §17.3.4 reassigns (clamps) an out-of-range line-border sz on render; the schema type is an unbounded unsigned decimal, so sz=200 is well-formed and valid and Word opens it without repair.",
    );
}

#[test]
fn para_shd_pattern_only_no_colors_resolves_and_opens_clean() {
    let body = r#"<w:p><w:pPr><w:shd w:val="pct20"/></w:pPr><w:r><w:t>pattern only</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ECMA §17.3.5 CT_Shd / §17.18.78 ST_Shd — ST_Shd marks only val as required; pct20 is an enumerated value and omitted color/fill resolve to auto, so the doc is well-formed/valid and Word opens it without repair.",
    );
    assert_eq!(
        accept_text(&b).trim(),
        "pattern only",
        "ECMA §17.3.5 CT_Shd — shading is a layout/background property and contributes no glyphs; with no tracked changes the accepted text equals the authored run text regardless of the pattern."
    );
}

